&lt;ul&gt;
&lt;li&gt;&lt;span data-sheets-value=&quot;{&amp;quot;1&amp;quot;:3,&amp;quot;3&amp;quot;:157000}&quot; data-sheets-userformat=&quot;{&amp;quot;2&amp;quot;:14589,&amp;quot;3&amp;quot;:{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;#,##0&amp;quot;,&amp;quot;3&amp;quot;:1},&amp;quot;5&amp;quot;:{&amp;quot;1&amp;quot;:[{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0,&amp;quot;5&amp;quot;:{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0}},{&amp;quot;1&amp;quot;:0,&amp;quot;2&amp;quot;:0,&amp;quot;3&amp;quot;:3},{&amp;quot;1&amp;quot;:1,&amp;quot;2&amp;quot;:0,&amp;quot;4&amp;quot;:1}]},&amp;quot;6&amp;quot;:{&amp;quot;1&amp;quot;:[{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0,&amp;quot;5&amp;quot;:{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0}},{&amp;quot;1&amp;quot;:0,&amp;quot;2&amp;quot;:0,&amp;quot;3&amp;quot;:3},{&amp;quot;1&amp;quot;:1,&amp;quot;2&amp;quot;:0,&amp;quot;4&amp;quot;:1}]},&amp;quot;7&amp;quot;:{&amp;quot;1&amp;quot;:[{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0,&amp;quot;5&amp;quot;:{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0}},{&amp;quot;1&amp;quot;:0,&amp;quot;2&amp;quot;:0,&amp;quot;3&amp;quot;:3},{&amp;quot;1&amp;quot;:1,&amp;quot;2&amp;quot;:0,&amp;quot;4&amp;quot;:1}]},&amp;quot;8&amp;quot;:{&amp;quot;1&amp;quot;:[{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0,&amp;quot;5&amp;quot;:{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:0}},{&amp;quot;1&amp;quot;:0,&amp;quot;2&amp;quot;:0,&amp;quot;3&amp;quot;:3},{&amp;quot;1&amp;quot;:1,&amp;quot;2&amp;quot;:0,&amp;quot;4&amp;quot;:1}]},&amp;quot;9&amp;quot;:1,&amp;quot;10&amp;quot;:1,&amp;quot;14&amp;quot;:{&amp;quot;1&amp;quot;:3,&amp;quot;3&amp;quot;:1},&amp;quot;15&amp;quot;:&amp;quot;Open Sans&amp;quot;,&amp;quot;16&amp;quot;:11}&quot; data-sheets-formula=&quot;=if(if(R[-10]C[-2]=&amp;quot;Hire&amp;quot;,iferror(round(R[0]C[-1]*1.1,-3),&amp;quot;&amp;quot;),iferror(round(R[0]C[-1]*1.2,-3),&amp;quot;&amp;quot;))=0,&amp;quot;&amp;quot;,if(R[-10]C[-2]=&amp;quot;Hire&amp;qu